from flask import Blueprint, render_template, request, redirect, url_for, flash, sessionfrom werkzeug.security import generate_password_hash, check_password_hashfrom helpers.utils import validate_email, validate_passwordfrom helpers.services import create_user, get_user_by_email, merge_guest_cartfrom datetime import datetimebp = Blueprint('auth', __name__)@bp.route('/signup', methods=['GET', 'POST'])def signup():    if request.method == 'POST':        username = request.form.get('username', '').strip()        email = request.form.get('email', '').strip().lower()        password = request.form.get('password', '')        if not username or not email or not password:            flash('All fields are required', 'error')            return render_template('signup.html')        if len(username) < 3:            flash('Username must be at least 3 characters', 'error')            return render_template('signup.html')        if not validate_email(email):            flash('Please enter a valid email address', 'error')            return render_template('signup.html')        ok, msg = validate_password(password)        if not ok:            flash(msg, 'error')            return render_template('signup.html')        if get_user_by_email(email):            flash('Email already registered', 'error')            return render_template('signup.html')        user = create_user(username, email, generate_password_hash(password))        if 'session_id' in session:            merge_guest_cart(session['session_id'], user.id)        session['user_id'] = user.id        flash(f'Welcome to XLOVEBEATS, {username}!', 'success')        return redirect(url_for('public.home'))    return render_template('signup.html')@bp.route('/login', methods=['GET', 'POST'])def login():    if request.method == 'POST':        email = request.form.get('email', '').strip().lower()        password = request.form.get('password', '')        if not email or not password:            flash('Email and password are required', 'error')            return render_template('login.html')        user = get_user_by_email(email)        if user and check_password_hash(user.password_hash, password):            user.last_login = datetime.utcnow()            session['user_id'] = user.id            flash(f'Welcome back, {user.username}!', 'success')            return redirect(url_for('public.home'))        flash('Invalid email or password', 'error')    return render_template('login.html')@bp.route('/logout')def logout():    session.pop('user_id', None)    flash('You have been logged out', 'info')    return redirect(url_for('public.home'))